:root {
  --bg: #ffffff;
  --border: #e8e8e8;
  --header-bg: #1a1a2e;
  --header-text: #ffffff;
  --count-bg: #2d2d4e;
  --count-text: #a0a0cc;
  --company-text: #1a1a2e;
  --role-text: #6b7280;
  --item-hover: #f9f9fb;
  --divider: #f0f0f4;
  --footer-bg: #f7f7fb;
  --stat-value: #1a1a2e;
  --stat-label: #9ca3af;

  --status-interview-bg: #dbeafe;
  --status-interview-text: #1d4ed8;
  --status-applied-bg: #f3f4f6;
  --status-applied-text: #374151;
  --status-offer-bg: #d1fae5;
  --status-offer-text: #065f46;
  --status-review-bg: #fef3c7;
  --status-review-text: #92400e;
  --status-rejected-bg: #fee2e2;
  --status-rejected-text: #991b1b;
}

.tracker {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  width: 460px;
  overflow: hidden;
}

.tracker-header {
  background: var(--header-bg);
  padding: 14px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.tracker-title {
  color: var(--header-text);
  font-size: 17px;
  font-weight: 700;
  letter-spacing: -0.3px;
}

.tracker-count {
  background: var(--count-bg);
  color: var(--count-text);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}

.job-list {
  padding: 8px 0;
}

.job-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 20px;
  border-bottom: 1px solid var(--divider);
}

.job-item:last-child {
  border-bottom: none;
}

.company {
  font-size: 14px;
  font-weight: 700;
  color: var(--company-text);
}

.role {
  font-size: 12px;
  color: var(--role-text);
  margin-top: 2px;
}

.status {
  font-size: 11px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 20px;
  letter-spacing: 0.2px;
}

.status--interview {
  background: var(--status-interview-bg);
  color: var(--status-interview-text);
}

.status--applied {
  background: var(--status-applied-bg);
  color: var(--status-applied-text);
}

.status--offer {
  background: var(--status-offer-bg);
  color: var(--status-offer-text);
}

.status--review {
  background: var(--status-review-bg);
  color: var(--status-review-text);
}

.status--rejected {
  background: var(--status-rejected-bg);
  color: var(--status-rejected-text);
}

.tracker-footer {
  background: var(--footer-bg);
  border-top: 1px solid var(--border);
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  padding: 12px 20px;
  gap: 8px;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 18px;
  font-weight: 800;
  color: var(--stat-value);
  line-height: 1;
}

.stat-label {
  font-size: 10px;
  font-weight: 500;
  color: var(--stat-label);
  text-align: center;
  line-height: 1.3;
}
